"use client";

/* ════════════════════════════════════════════════════════════════════════
   <ContributionCascade> — the P&L margin walk (Tier-1, CHART-STANDARD §5).

   Question it answers: where does revenue become profit?
   Instrument form: milled waterfall (revenue → COGS → CM1/2 → operations → net),
   dashed connectors, gridlines, hover-to-inspect step readout.

   Data contract (§4):
     - `data` prop typed as ContributionStep[]
     - `sampleContributionData` exported with the EXACT real shape
     - Revenue + running margins are DERIVED inside the component
     - No hardcoded numbers in render

   States (§2 rule 5):
     - Routes through <ChartStates> for loading/empty/partial/error
   ──────────────────────────────────────────────────────────────────────── */

import { useMemo, useState } from "react";
import { useChartSize } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export type ContributionStepType = "start" | "cost" | "rest" | "prof";

export interface ContributionStep {
  label: string;
  /** Value in $K. Costs are negative, rests + final are running margin. */
  val: number;
  type: ContributionStepType;
  /** Margin-percent note shown beside the value (e.g. "80.4%"). Optional. */
  note?: string;
  /** Tiny sub-label under the step name (e.g. "payroll·rent·sw"). Optional. */
  sub?: string;
  /** One-sentence read for the readout zone. */
  desc: string;
}

export interface ContributionCascadeProps {
  data?: ContributionStep[];
  state?: ChartState;
  /** Click a step — e.g. open Bridge / Study scoped to that step. */
  onStepClick?: (stepIndex: number, step: ContributionStep) => void;
  /** Title used in empty/error copy. */
  label?: string;
}

export const sampleContributionData: ContributionStep[] = [
  { label: "Revenue",      val: 453, type: "start", desc: "Top line — every dollar that came in before any cost." },
  { label: "COGS",         val: -89, type: "cost",  desc: "Cost of goods — what the products themselves cost to make or buy." },
  { label: "Gross margin", val: 364, type: "rest",  note: "80.4%", desc: "What's left after product cost. The ceiling everything else comes out of." },
  { label: "Shipping",     val: -12, type: "cost",  desc: "Delivery and fulfilment to get orders out the door." },
  { label: "CM1",          val: 352, type: "rest",  note: "77.7%", desc: "Contribution after product + shipping — margin before you spend to acquire." },
  { label: "Marketing",    val: -33, type: "cost",  desc: "Ad spend and promotion to bring the orders in." },
  { label: "CM2",          val: 319, type: "rest",  note: "70.4%", desc: "What survives after acquisition cost — the true unit economics." },
  { label: "Operations",   val: -79, type: "cost",  sub: "payroll·rent·sw", desc: "Running the business — payroll, rent, and software combined." },
  { label: "Net profit",   val: 240, type: "prof",  note: "53.0%", desc: "The dollar that's actually yours after every cost this month." },
];

const fmtK = (v: number) => (v < 0 ? "−$" : "$") + Math.abs(v) + "K";

export function ContributionCascade({
  data = sampleContributionData,
  state = "ready",
  onStepClick,
  label = "Contribution cascade",
}: ContributionCascadeProps) {
  const { ref, width } = useChartSize({ min: 640, fallback: 920 });
  const [hovered, setHovered] = useState<number | null>(null);

  const W = Math.max(640, width);
  const H = 236;
  const padL = 46;
  const padR = 14;
  const padT = 26;
  const padB = 34;
  const plotW = W - padL - padR;
  const plotH = H - padT - padB;
  const base = padT + plotH;

  // Derive: revenue, max-scale, running margin after each step. NEVER passed in.
  const revenue = useMemo(
    () => data.find((s) => s.type === "start")?.val ?? 0,
    [data],
  );
  const maxV = useMemo(() => {
    const top = Math.max(...data.map((s) => Math.abs(s.val)));
    // round up to a clean grid value
    return Math.ceil(top / 60) * 60 || 480;
  }, [data]);
  const runAfter = useMemo(() => {
    const arr: number[] = [];
    let running = 0;
    data.forEach((s) => {
      if (s.type === "start") running = s.val;
      else if (s.type === "cost") running += s.val;
      else running = s.val;
      arr.push(running);
    });
    return arr;
  }, [data]);
  const profit = useMemo(
    () => data.find((s) => s.type === "prof")?.val ?? runAfter[runAfter.length - 1] ?? 0,
    [data, runAfter],
  );

  const y = (v: number) => base - (v / maxV) * plotH;
  const n = data.length;
  const gap = Math.max(12, W * 0.016);
  const colW = n > 0 ? (plotW - gap * (n - 1)) / n : plotW;
  const xL = (i: number) => padL + i * (colW + gap);
  const xC = (i: number) => xL(i) + colW / 2;

  const gridSteps = 4;
  const gridVals = Array.from({ length: gridSteps + 1 }, (_, i) => (maxV * i) / gridSteps);

  // Connectors between bars
  const connectors: { x1: number; y1: number; x2: number; y2: number }[] = [];
  let prevRightX: number | null = null;
  let prevConnY = 0;
  data.forEach((s, i) => {
    let topY: number;
    let botY: number;
    const running = i === 0 ? s.val : runAfter[i];
    if (s.type === "start" || s.type === "rest" || s.type === "prof") {
      topY = y(s.val);
      botY = base;
    } else {
      const from = i === 0 ? 0 : runAfter[i - 1];
      topY = y(from);
      botY = y(running);
    }
    if (prevRightX !== null) {
      connectors.push({ x1: prevRightX, y1: prevConnY, x2: xL(i), y2: topY });
    }
    prevConnY = s.type === "cost" ? botY : topY;
    prevRightX = xL(i) + colW;
  });

  return (
    <div className="cc-walk">
      <div className="cc-head">
        <div className="cc-kicker">Revenue → gross margin → CM1 → CM2 → net profit</div>
        <div className="cc-ends">
          <span className="e rev">{fmtK(revenue)} revenue</span>
          <span className="arr">→</span>
          <span className="e prof">{fmtK(profit)} profit</span>
        </div>
      </div>

      <div className="cc-chart" ref={ref}>
        <ChartStates state={state} height={H} label={label}>
          <svg
            className={`cc-svg${hovered !== null ? " dimmed" : ""}`}
            viewBox={`0 0 ${W} ${H}`}
            onMouseLeave={() => setHovered(null)}
          >
            {/* gridlines + axis labels */}
            {gridVals.map((v) => {
              const yy = y(v);
              return (
                <g key={v}>
                  <line className="cc-grid" x1={padL} y1={yy} x2={W - padR} y2={yy} />
                  <text className="cc-grid-lab" x={padL - 7} y={yy + 3} textAnchor="end">
                    ${v}K
                  </text>
                </g>
              );
            })}

            {connectors.map((c, i) => (
              <line key={i} className="cc-conn" x1={c.x1} y1={c.y1} x2={c.x2} y2={c.y2} />
            ))}

            <line className="cc-base" x1={padL} y1={base} x2={W - padR} y2={base} />

            {data.map((s, i) => {
              let topY: number;
              let botY: number;
              let cls = "";
              let valCls = "";
              let valTxt = "";
              if (s.type === "start") {
                topY = y(s.val);
                botY = base;
                cls = "cc-bar-start";
                valCls = "pos";
                valTxt = "$" + s.val + "K";
              } else if (s.type === "cost") {
                const from = i === 0 ? 0 : runAfter[i - 1];
                topY = y(from);
                botY = y(runAfter[i]);
                cls = "cc-bar-cost";
                valCls = "cost";
                valTxt = s.val + "K";
              } else if (s.type === "rest") {
                topY = y(s.val);
                botY = base;
                cls = "cc-bar-rest";
                valCls = "rest";
                valTxt = "$" + s.val + "K";
              } else {
                topY = y(s.val);
                botY = base;
                cls = "cc-bar-prof";
                valCls = "prof";
                valTxt = "$" + s.val + "K";
              }
              const h = Math.max(botY - topY, 2);
              const isOn = hovered === i;
              return (
                <g
                  key={i}
                  className={`cc-step${isOn ? " on" : ""}`}
                  onMouseEnter={() => setHovered(i)}
                  onClick={() => onStepClick?.(i, s)}
                  style={onStepClick ? { cursor: "pointer" } : undefined}
                >
                  <rect className={cls} x={xL(i)} y={topY} width={colW} height={h} rx={2} />
                  <text className={`cc-val ${valCls}`} x={xC(i)} y={topY - 8} textAnchor="middle">
                    {valTxt}
                    {s.note && <tspan className="cc-note"> {s.note}</tspan>}
                  </text>
                  <text className="cc-label" x={xC(i)} y={base + 15} textAnchor="middle">
                    {s.label.toUpperCase()}
                  </text>
                  {s.sub && (
                    <text className="cc-label-sub" x={xC(i)} y={base + 25} textAnchor="middle">
                      {s.sub}
                    </text>
                  )}
                  {/* full-column hover hit area */}
                  <rect
                    x={xL(i)}
                    y={padT}
                    width={colW}
                    height={base - padT}
                    fill="transparent"
                  />
                </g>
              );
            })}
          </svg>
        </ChartStates>
      </div>

      <div className="cc-readout">
        {hovered === null ? (
          <span className="cc-empty">Hover any step to see what it does to the margin</span>
        ) : (
          (() => {
            const s = data[hovered];
            const isCost = s.type === "cost";
            const after = runAfter[hovered];
            if (isCost) {
              const pct = ((Math.abs(s.val) / Math.max(1, revenue)) * 100).toFixed(1);
              return (
                <div className="cc-card">
                  <div className="cc-block">
                    <span className="cc-l">{s.label}</span>
                    <span className="cc-v cost">{fmtK(s.val)}</span>
                  </div>
                  <div className="cc-block">
                    <span className="cc-l">Share of revenue</span>
                    <span className="cc-v">{pct}%</span>
                  </div>
                  <div className="cc-block">
                    <span className="cc-l">Margin after</span>
                    <span className="cc-v">${after}K</span>
                  </div>
                  <div className="cc-arg">{s.desc}</div>
                </div>
              );
            }
            const pct = ((s.val / Math.max(1, revenue)) * 100).toFixed(1);
            const isProf = s.type === "prof";
            return (
              <div className="cc-card">
                <div className="cc-block">
                  <span className="cc-l">{s.label}</span>
                  <span className={`cc-v${isProf ? " green" : ""}`}>${s.val}K</span>
                </div>
                <div className="cc-block">
                  <span className="cc-l">Of revenue</span>
                  <span className={`cc-v${isProf ? " green" : ""}`}>{pct}%</span>
                </div>
                <div className="cc-arg">{s.desc}</div>
              </div>
            );
          })()
        )}
      </div>
    </div>
  );
}
