"use client";

import { useRef, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import {
  ContributionCascade,
  type ContributionStep,
} from "@/components/charts/ContributionCascade";
import "@/components/charts/ContributionCascade.css";
import { Per100StackBar } from "@/components/charts/Per100StackBar";
import {
  walkSteps,
  per100Segments,
  costRows,
  costTotals,
  anomalies,
  plMetrics,
  plAI,
  modelSpend,
  GM_CONST,
  gmCrossDept,
} from "@/features/finance/api/finance-pl-data";
import "./pl.css";

const PERIOD_LABELS = ["This month", "Last month", "Last 3 months", "YTD"];
const PERIOD_ANOM_LABELS = ["this month", "last month", "over the last 3 months", "year to date"];

export default function PLPage() {
  const [periodIdx, setPeriodIdx] = useState(1);
  const [gmReporting, setGmReporting] = useState(false);
  const [spend, setSpend] = useState(GM_CONST.RECOMMENDED);

  return (
    <div className="finance-pl-page">
      <DeptHeader
        dept="finance"
        title="Profit & Loss"
        meta={
          <>
            <span className="live">Live</span> · True profit after every cost · from orders + ledger
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="finance">Review costs →</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      {/* Metrics */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Revenue</div>
          <div className="metric-v">{plMetrics.revenue}</div>
          <div className="metric-s up">{plMetrics.revenueDelta}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Total costs</div>
          <div className="metric-v">{plMetrics.totalCosts}</div>
          <div className="metric-s down">{plMetrics.totalCostsDelta}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Net profit</div>
          <div className="metric-v green">{plMetrics.netProfit}</div>
          <div className="metric-s up">{plMetrics.netProfitDelta}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Net margin</div>
          <div className="metric-v green">{plMetrics.netMargin}</div>
          <div className="metric-s">{plMetrics.grossNote}</div>
        </div>
      </div>

      <AIStrip label={plAI.label} meta={plAI.meta} cards={plAI.cards} />

      {/* MARGIN WALK — <ContributionCascade> Tier-1 chart per CHART-STANDARD §5 */}
      <SectionLabel>The margin walk — from revenue to profit</SectionLabel>
      <ContributionCascade data={walkSteps as ContributionStep[]} />

      {/* per $100 — Tier-2 supporting chart */}
      <Per100StackBar data={per100Segments} />

      {/* COST BREAKDOWN */}
      <SectionLabel>Full cost breakdown</SectionLabel>
      <div className="costs">
        {costRows.map((r, i) => (
          <div key={i} className="cost-row">
            <div className="cost-name">
              <span className="dot" style={{ background: r.dot }} />
              <span className="nm">{r.nm}</span>
              {r.tag && (
                <span className={`tag ${r.tag}`}>
                  {r.tag === "var" ? "Variable" : "Fixed"}
                </span>
              )}
            </div>
            <div className="pct">
              {r.pct}
              {r.delta && <span className={`delta ${r.dc ?? "flat"}`}>{r.delta}</span>}
            </div>
            <div className="amt">{r.amt}</div>
          </div>
        ))}
        <div className="cost-row tot">
          <div className="cost-name">
            <span className="nm">Total costs</span>
          </div>
          <div className="pct" />
          <div className="amt">{costTotals.totalCosts}</div>
        </div>
        <div className="cost-row net">
          <div className="cost-name">
            <span className="nm">Net profit</span>
          </div>
          <div className="pct" style={{ color: "var(--d-finance)" }}>
            {costTotals.netMarginText}
          </div>
          <div className="amt">{costTotals.netProfit}</div>
        </div>
      </div>

      {/* ANOMALIES */}
      <SectionLabel>
        Cost anomalies — what changed {PERIOD_ANOM_LABELS[periodIdx]}
      </SectionLabel>
      <div className="anom">
        {anomalies.map((a, i) => (
          <div key={i} className="anom-row">
            <div className="anom-top">
              <span className="dot" />
              <span className="nm">{a.name}</span>
              <span className="delta">{a.delta}</span>
            </div>
            <div className="anom-desc">{a.desc}</div>
            <div className="anom-q">{a.question}</div>
          </div>
        ))}
      </div>

      {/* GROWTH MODE */}
      <SectionLabel>Growth Mode — can you afford to scale acquisition?</SectionLabel>
      <GrowthMode
        spend={spend}
        setSpend={setSpend}
        reporting={gmReporting}
        setReporting={setGmReporting}
      />
    </div>
  );
}

/* ─────────────────────────────────────────────────
   GrowthMode — the planning slider + projections
   ───────────────────────────────────────────────── */
function GrowthMode({
  spend,
  setSpend,
  reporting,
  setReporting,
}: {
  spend: number;
  setSpend: (v: number) => void;
  reporting: boolean;
  setReporting: (v: boolean) => void;
}) {
  const sliderRef = useRef<HTMLDivElement>(null);
  const model = modelSpend(spend);
  const pct = (spend / GM_CONST.MAX_SPEND) * 100;
  const ceilingPct = (GM_CONST.CEILING / GM_CONST.MAX_SPEND) * 100;

  const verdictClass =
    model.zone === "near" ? "near" : model.zone === "past" ? "past" : "scale";
  const badgeText =
    model.zone === "near"
      ? "Near ceiling"
      : model.zone === "past"
      ? "Past ceiling"
      : "Room to scale";
  const verdictBody =
    model.zone === "past"
      ? "You're spending past the safe ceiling. Payback exceeds 6 months — every new dollar of acquisition cost takes longer to recover than your margin can comfortably carry."
      : model.zone === "near"
      ? "You're approaching the ceiling. Payback is creeping above the comfort threshold — scaling further means cash recovers slower than you'd want."
      : "Your unit economics support spending more on acquisition. CAC pays back in 3.1 months against a 14-month customer lifetime — every $1 of margin can fund growth before it's at risk.";

  const paybackCls =
    model.zone === "past" ? "red" : model.zone === "near" ? "amber" : "green";

  const updateFromEvent = (clientX: number) => {
    const el = sliderRef.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const ratio = Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
    setSpend(ratio * GM_CONST.MAX_SPEND);
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    (e.currentTarget as HTMLDivElement).setPointerCapture(e.pointerId);
    updateFromEvent(e.clientX);
  };
  const handlePointerMove = (e: React.PointerEvent) => {
    if (e.buttons !== 1) return;
    updateFromEvent(e.clientX);
  };

  return (
    <div className={`gm${reporting ? " reporting" : ""}`}>
      <div className="gm-head">
        <div className="gm-head-left">
          <div className="gm-icon">
            <svg
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <path d="M3 17 L9 11 L13 15 L21 7" />
              <path d="M15 7 H21 V13" />
            </svg>
          </div>
          <div>
            <div className="gm-title">Growth Mode</div>
            <div className="gm-sub">Finance × Growth · acquisition economics</div>
          </div>
        </div>
        <button
          type="button"
          className="gm-toggle"
          onClick={() => setReporting(!reporting)}
          aria-pressed={reporting}
        >
          <span>{reporting ? "Reporting view" : "Planning view"}</span>
          <span className="gm-switch" />
        </button>
      </div>

      <div className={`gm-verdict ${verdictClass}`}>
        <span className="vbadge">{badgeText}</span>
        <span
          className="vtext"
          dangerouslySetInnerHTML={{
            __html:
              model.zone === "scale"
                ? verdictBody.replace("more", "<b>more</b>")
                : verdictBody,
          }}
        />
      </div>

      <div className="gm-metrics">
        <div className="gm-metric">
          <div className="gk">LTV</div>
          <div className="gv">$340</div>
          <div className="gs">12-mo projected</div>
        </div>
        <div className="gm-metric">
          <div className="gk">CAC</div>
          <div className="gv">$92</div>
          <div className="gs">blended, last 30 days</div>
        </div>
        <div className="gm-metric">
          <div className="gk">LTV : CAC</div>
          <div className="gv green">3.7×</div>
          <div className="gs">healthy above 3.0×</div>
        </div>
        <div className="gm-metric">
          <div className="gk">Payback</div>
          <div className={`gv ${paybackCls}`}>
            {model.payback.toFixed(1)} <span className="u">mo</span>
          </div>
          <div className="gs">target under 6 mo</div>
        </div>
      </div>

      <div className="gm-alloc">
        <div className="gm-alloc-head">
          <div className="ak">Monthly acquisition spend — drag to model</div>
          <div className="av">
            Now $33K → <span className="rec">${Math.round(spend)}K</span>
          </div>
        </div>
        <div
          className="gm-slider"
          ref={sliderRef}
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
        >
          <div className="gm-track">
            <div className="rec-fill" style={{ width: `${pct}%` }} />
          </div>
          <div className="gm-ceiling" style={{ left: `${ceilingPct}%` }}>
            <span className="cl">Ceiling $60K — payback hits 6mo</span>
          </div>
          <div className="gm-handle" style={{ left: `${pct}%` }} />
        </div>
        <div className="gm-scale">
          <span>$0</span>
          <span>$30K</span>
          <span>$60K</span>
          <span>$75K</span>
        </div>
      </div>

      <div className="gm-foot">
        <div className="gm-proj">
          <div className="gm-proj-head">At ${Math.round(spend)}K/mo</div>
          <div className="gm-proj-grid">
            <div className="gm-proj-item">
              <div className="pv green">+{model.addCust}</div>
              <div className="pk">new customers / mo</div>
            </div>
            <div className="gm-proj-item">
              <div className="pv green">+${model.ltvAdd}K</div>
              <div className="pk">12-mo LTV added</div>
            </div>
            <div className="gm-proj-item">
              <div className={`pv ${paybackCls}`}>{model.payback.toFixed(1)} mo</div>
              <div className="pk">CAC payback</div>
            </div>
          </div>
        </div>
        <div className="gm-cross">
          <div className="gm-cross-head">What this touches</div>
          {gmCrossDept.map((c, i) => (
            <div key={i} className="gm-cross-row">
              <span className="cd" style={{ background: c.dot }} />
              <span dangerouslySetInnerHTML={{ __html: c.text.replace(/^(\w+)/, "<b>$1</b>") }} />
            </div>
          ))}
        </div>
      </div>

      <div className="gm-actions">
        <span className="note">
          A planning instrument — projections are estimates, and nothing here changes
          your spend. Scaling happens in Growth, with full context.
        </span>
      </div>
    </div>
  );
}
