"use client";

/**
 * <Per100StackBar> — the "for every $100 your store earns" milled stack.
 *
 * Tier-2 supporting instrument per CHART-STANDARD §5.1. Deliberately simple:
 * one-glance dollar split, no crosshair, no beacon.  Sums must reconcile to
 * 100 — enforced inside the component.
 */

import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface Per100Segment {
  /** Label shown in the legend, e.g. "COGS" */
  k: string;
  /** Width in dollars of every $100 (must sum to 100 across all segments) */
  v: number;
  /** Fill color — token or hex */
  c: string;
}

export interface Per100StackBarProps {
  data?: Per100Segment[];
  state?: ChartState;
  /** label used in empty/error copy */
  label?: string;
}

export const samplePer100Data: Per100Segment[] = [
  { k: "COGS", v: 20, c: "var(--cost-cogs)" },
  { k: "Delivery", v: 3, c: "var(--cost-delivery)" },
  { k: "Marketing", v: 7, c: "var(--cost-mktg)" },
  { k: "Payroll", v: 10, c: "var(--cost-pay)" },
  { k: "Rent", v: 5, c: "var(--cost-rent)" },
  { k: "Software/Other", v: 2, c: "var(--cost-soft)" },
  { k: "Profit", v: 53, c: "var(--d-finance)" },
];

export function Per100StackBar({
  data = samplePer100Data,
  state = "ready",
  label = "Per $100",
}: Per100StackBarProps) {
  // §4: data must reconcile to its total
  const sum = data.reduce((acc, s) => acc + s.v, 0);
  const ok = Math.abs(sum - 100) < 0.01;

  return (
    <div className="per100">
      <div className="per100-head">For every $100 your store earns</div>
      <ChartStates state={state} height={42} label={label}>
        {ok ? (
          <>
            <div className="per100-bar">
              {data.map((s, i) => (
                <div
                  key={i}
                  className="per100-seg"
                  style={{ width: `${s.v}%`, background: s.c }}
                  aria-label={`${s.k} ${s.v} dollars`}
                >
                  <span className="pv">${s.v}</span>
                </div>
              ))}
            </div>
            <div className="per100-legend">
              {data.map((s, i) => (
                <span key={i} className="pl">
                  <i style={{ background: s.c }} />
                  {s.k} · ${s.v}
                </span>
              ))}
            </div>
          </>
        ) : (
          <div className="per100-bad">
            Segments don&rsquo;t sum to $100 (got ${sum.toFixed(1)}) — fix the data.
          </div>
        )}
      </ChartStates>
    </div>
  );
}
