/**
 * Mock data for Finance · P&L (Profit & Loss).
 *
 * Two interactive surfaces drive this page:
 *
 *   1. The **margin walk** — a waterfall from revenue down through every
 *      cost class to net profit. Hovering a step dims the others and
 *      surfaces a readout with the step's share of revenue and the
 *      margin that survives.
 *
 *   2. **Growth Mode** — a planning slider that models acquisition spend
 *      against payback and added LTV. The slider is purely model-driven;
 *      payback degrades non-linearly past the recommended point.
 */

export interface WalkStep {
  label: string;
  /** Dollar value in $K. Costs are negative, rests + final are running margin. */
  val: number;
  type: "start" | "cost" | "rest" | "prof";
  /** Margin-percent note shown beside the value (e.g. "80.4%"). */
  note?: string;
  /** Tiny sub-label under the step name (e.g. "payroll·rent·sw"). */
  sub?: string;
  /** One-sentence read for the readout zone. */
  desc: string;
}

