/* ─── Growth Mode model ─── */
export const GM_CONST = {
  MAX_SPEND: 75, // $K
  CEILING: 60,
  CURRENT: 33,
  RECOMMENDED: 46,
  LTV: 340,
};

export interface GMResult {
  addCust: number;
  ltvAdd: number;
  payback: number;
  zone: "scale" | "near" | "past";
}

/**
 * Model acquisition outcomes at a given monthly spend.
 * - addCust: new customers/mo at this spend, *incremental* vs current
 * - ltvAdd: total 12-mo LTV those customers add, in $K
 * - payback: months to recover CAC from contribution margin
 * - zone: drives the verdict badge color/copy
 */
export function modelSpend(spend: number): GMResult {
  const { MAX_SPEND, CEILING, CURRENT, RECOMMENDED, LTV } = GM_CONST;
  spend = Math.max(0, Math.min(MAX_SPEND, spend));
  const custPerK = 100 / 33;
  const addCust = Math.max(0, Math.round((spend - CURRENT) * custPerK * 0.92));
  const ltvAdd = Math.max(0, Math.round((addCust * LTV) / 1000));
  let payback: number;
  if (spend <= RECOMMENDED) payback = 2.6 + ((spend - CURRENT) / (RECOMMENDED - CURRENT)) * 0.5;
  else if (spend <= CEILING) payback = 3.1 + ((spend - RECOMMENDED) / (CEILING - RECOMMENDED)) * 2.9;
  else payback = 6.0 + ((spend - CEILING) / (MAX_SPEND - CEILING)) * 3.5;
  let zone: GMResult["zone"];
  if (payback <= 4.5) zone = "scale";
  else if (payback <= 6.0) zone = "near";
  else zone = "past";
  return { addCust, ltvAdd, payback, zone };
}

